INSERT INTO "Show" (title, slug, theatre, "durationMinutes", summary, description, "cast") VALUES ('אמוק', 'אמוק', 'תיאטרון מלנקי', 75, 'דרמה פסיכולוגית מרתקת על רופא שחי בבדידות עד שמופיעה אישה המובילה אותו לסחרור רגשית מסוכנת.', 'שני גברים נפגשים בלילה סוער על ספינה המפליגה לאירופה. אחד מהם, רופא שחי בבדידות ובשעמום, מתמודד עם טירוף אהבה קטלני בעקבות הופעתה של אישה יפה ואצילית. דרמה פסיכולוגית מסעירה עפ״י הנובלה של שטפן צוויג.', 'דודו ניב') ON CONFLICT (slug) DO NOTHING;
INSERT INTO "Show" (title, slug, theatre, "durationMinutes", summary, description, "cast") VALUES ('האף האדום שלי', 'האף-האדום-שלי', 'תיאטרון מלנקי', 80, 'הצגה דוקומנטרית מרגשת ומטלטלת, המביאה אל הבמה את סיפוריהם של הרופאים, הצוותים הרפואיים, המטופלים והליצנים הרפואיים בבית החולים ברזילי, במהלך השבועות הראשונים של המלחמה.', 'ב-7 באוקטובר 2023, בזמן שבית החולים ברזילי באשקלון המשיך לפעול תחת מתקפת טילים, הצוותים הרפואיים נאלצו להתמודד עם זרם בלתי פוסק של פצועים – חיילים, אזרחים, שוטרים – ועם משפחות חסרות אונים שחיפשו את יקיריהן. בתוך הכאוס הזה, לצד הרופאים והאחיות, היו

גם הליצנים הרפואיים. מה תפקידו של ליצן רפואי בתוך מציאות של כאב ואובדן? איך ממשיכים לחייך כשהכול מסביב קורס? איליה דומנוב, ליצן רפואי בבית החולים ברזילי למעלה מעשור, תיעד את החוויות שלו ושל חבריו באמצעות  ראיונות עם אנשי צוות רפואי, מטופלים וליצנים רפואיים. מתוך החומרים האלה נוצרה הצגה עוצמתית ובלתי נשכחת, המבוססת על עדויות שנבחרו בקפידה ומספרות את סיפור הימים הראשונים של המלחמה מנקודת מבט אנושית וחיה.
דרך עיניו של ליצן רפואי, ההצגה חושפת את ההתמודדות היומיומית עם הפצועים, עם הבלבול, עם החרדה, וגם עם רגעי החסד הקטנים שמעניקים תקווה בתוך הכאב. זהו סיפור של אנשים שהפכו לעדים בעל כורחם, של מי שנשארו מאחור ושל מי שנלחמו להציל חיים, לא רק בגוף אלא גם בנפש.', 'איליה דומנוב, הלנה ירלובה, אנה דוברוביצקי, נטליה גנטמן, אורי לבנון') ON CONFLICT (slug) DO NOTHING;
INSERT INTO "Show" (title, slug, theatre, "durationMinutes", summary, description, "cast") VALUES ('שפירא', 'שפירא', 'תיאטרון מלנקי', 105, 'דרמה חודרת על זהות יהודית והשפעותיה המורכבות על חיי הפרט. אתה יכול להיראות כמו ג''נטלמן אירופי אמיתי אבל בנסיבות מסוימות תמיד יזכירו לך שאתה יהודי וההשלכות יכולות להיות בלתי צפויות.', 'משה (מוזס וילהלם) שפירא, אספן וסוחר עתיקות, איש יהודי מומר החי ופועל
בלב ירושלים העתיקה במחצית השנייה של המאה ה-19.
בשנת 1883, הפתיע שפירא את העולם המדעי עם הצעה מיוחדת במינה  –שפירא  מציע למכור למוזיאון הבריטי בלונדון אוסף מגילות עתיקות שהתגלו, לכאורה, במערות באזור ים המלח.
המגילות מהוות כתב היד המקראי הקדום ביותר שנתגלה עד אז. במגילות הופיעה גרסה שונה במקצת של ספר דברים מזו שבנוסח המסורה המוכר לנו. שפירא דורש  מחיר מופקע עבור המגילות – מיליון ליש"ט
אבל ברגע אחרון מוטל ספק במקוריות של המגילות וכל הסיפור מקבל פרספקטיבה שונה.
 
כ-65 שנה לאחר תגליתו של שפירא התגלו במערות קומראן מגילות ים המלח. הם הוכיחו את יכולת הישמרותן של יריעות עור בכדים חתומים.
מאז גילוי מגילות ים המלח, החלו לעלות קולות מדענים לבחון מחדש את פרשת מגילות שפירא.
 
הסיפור של מגילות שפירא הוא סיפור תעלומות, מסקרן ועוצר נשימה, עטוף בזיכרונות של בתו, הסופרת מרים הרי (מחברת של הספר "בת ירושלים הקטנה"), שמתמודדת עם האמת שמתגלה בהדרגה תוך כדי צלילה אל תוך מעמקי הזיכרון.
אכן, זהו גם סיפור של התבוללות יהודי שמנסה להיות ג''נטלמן אירופאי אך הסביבה בכל זאת רואה בו יהודי קטן ונוכל.

​', 'הלנה ירלובה, דודו ניב, נטליה גנטמן, הדס אייל, אורי לבנון, דימה רוס') ON CONFLICT (slug) DO NOTHING;

